// // This D flip-flop captures the input data on the falling edge of the clock signal and outputs it.
module d_ff_sync_reset(clk, reset, d, q);

    input  clk;  
    input  reset;  
    input  d;
    output  q;
    reg   q; 

    always @(posedge clk)
          begin
            if (reset)
                q <= 0;
            else
                q <= d;
          end  

endmodule
